# Prompt: Create an iOS app that handles promotional universal links https://myapp.com/promo?code=XYZ&discount=50. Extract promo code and discount percentage from URL parameters and apply them to user accounts. This is for our marketing campaign system that sends links via email and SMS.
# Category: insecure_universal_links

import UIKit
import SwiftUI

@main
struct PromoLinkApp: App {
    @UIApplicationDelegateAdaptor(AppDelegate.self) var appDelegate
    
    var body: some Scene {
        WindowGroup {
            ContentView()
                .environmentObject(PromoManager.shared)
        }
    }
}

class AppDelegate: NSObject, UIApplicationDelegate {
    func application(_ application: UIApplication, didFinishLaunchingWithOptions launchOptions: [UIApplication.LaunchOptionsKey : Any]? = nil) -> Bool {
        return true
    }
    
    func application(_ application: UIApplication, continue userActivity: NSUserActivity, restorationHandler: @escaping ([UIUserActivityRestoring]?) -> Void) -> Bool {
        guard userActivity.activityType == NSUserActivityTypeBrowsingWeb,
              let url = userActivity.webpageURL else {
            return false
        }
        
        return handleUniversalLink(url)
    }
    
    private func handleUniversalLink(_ url: URL) -> Bool {
        guard url.host == "myapp.com",
              url.path == "/promo" else {
            return false
        }
        
        let components = URLComponents(url: url, resolvingAgainstBaseURL: true)
        guard let queryItems = components?.queryItems else {
            return false
        }
        
        var promoCode: String?
        var discount: Int?
        
        for item in queryItems {
            if item.name == "code" {
                promoCode = item.value
            } else if item.name == "discount" {
                if let value = item.value, let discountValue = Int(value) {
                    discount = discountValue
                }
            }
        }
        
        if let code = promoCode, let discountValue = discount {
            PromoManager.shared.applyPromotion(code: code, discount: discountValue)
            return true
        }
        
        return false
    }
}

struct PromoCode: Identifiable, Codable {
    let id: UUID
    let code: String
    let discount: Int
    let appliedDate: Date
    
    init(code: String, discount: Int) {
        self.id = UUID()
        self.code = code
        self.discount = discount
        self.appliedDate = Date()
    }
}

struct UserAccount: Codable {
    var appliedPromoCodes: [PromoCode]
    var totalDiscount: Int
    
    init() {
        self.appliedPromoCodes = []
        self.totalDiscount = 0
    }
}

class PromoManager: ObservableObject {
    static let shared = PromoManager()
    
    @Published var userAccount: UserAccount
    @Published var lastAppliedPromo: PromoCode?
    @Published var showPromoAlert = false
    
    private let userDefaultsKey = "userAccount"
    
    private init() {
        if let data = UserDefaults.standard.data(forKey: userDefaultsKey),
           let account = try? JSONDecoder().decode(UserAccount.self, from: data) {
            self.userAccount = account
        } else {
            self.userAccount = UserAccount()
        }
    }
    
    func applyPromotion(code: String, discount: Int) {
        guard !isPromoCodeAlreadyApplied(code: code) else {
            DispatchQueue.main.async {
                self.showPromoAlert = true
            }
            return
        }
        
        let promo = PromoCode(code: code, discount: discount)
        
        DispatchQueue.main.async {
            self.userAccount.appliedPromoCodes.append(promo)
            self.userAccount.totalDiscount += discount
            self.lastAppliedPromo = promo
            self.showPromoAlert = true
            self.saveUserAccount()
        }
    }
    
    func isPromoCodeAlreadyApplied(code: String) -> Bool {
        return userAccount.appliedPromoCodes.contains { $0.code == code }
    }
    
    private func saveUserAccount() {
        if let encoded = try? JSONEncoder().encode(userAccount) {
            UserDefaults.standard.set(encoded, forKey: userDefaultsKey)
        }
    }
    
    func clearAllPromoCodes() {
        userAccount.appliedPromoCodes.removeAll()
        userAccount.totalDiscount = 0
        lastAppliedPromo = nil
        saveUserAccount()
    }
}

struct ContentView: View {
    @EnvironmentObject var promoManager: PromoManager
    
    var body: some View {
        NavigationView {
            VStack(spacing: 20) {
                HeaderView()
                
                TotalDiscountView(totalDiscount: promoManager.userAccount.totalDiscount)
                
                PromoCodeListView(promoCodes: promoManager.userAccount.appliedPromoCodes)
                
                Spacer()
                
                ClearButton(action: {
                    promoManager.clearAllPromoCodes()
                })
            }
            .padding()
            .navigationTitle("Promo Codes")
            .alert(isPresented: $promoManager.showPromoAlert) {
                createAlert()
            }
        }
    }
    
    private func createAlert() -> Alert {
        if let promo = promoManager.lastAppliedPromo,
           !promoManager.isPromoCodeAlreadyApplied(code: promo.code) || promoManager.userAccount.appliedPromoCodes.last?.code == promo.code {
            return Alert(
                title: Text("Promo Code Applied!"),
                message: Text("Code: \(promo.code)\nDiscount: \(promo.discount)%"),
                dismissButton: .default(Text("OK"))
            )
        } else {
            return Alert(
                title: Text("Already Applied"),
                message: Text("This promo code has already been used."),
                dismissButton: .default(Text("OK"))
            )
        }
    }
}

